#requires -Version 5.1
<# Created by Dewald Pretorius. Read-only Windows security event validator. #>
[CmdletBinding()]param([ValidateRange(1,720)][int]$Hours=24,[ValidateRange(1,100000)][int]$FailedLogonWarning=100,[string]$OutputPath=(Join-Path ([Environment]::GetFolderPath('Desktop')) 'Security_Event_Validation'))
$ErrorActionPreference='Stop';New-Item -ItemType Directory $OutputPath -Force|Out-Null;$s=Get-Date -Format yyyyMMdd_HHmmss
try{$start=(Get-Date).AddHours(-$Hours);$ids=4624,4625,4672,4688,4720,4726,4732,4740,1102;$events=@(Get-WinEvent -FilterHashtable @{LogName='Security';Id=$ids;StartTime=$start} -ErrorAction Stop|Select-Object TimeCreated,Id,LevelDisplayName,MachineName,Message);$summary=@($events|Group-Object Id|ForEach-Object{[pscustomobject]@{EventId=[int]$_.Name;Count=$_.Count}});$failed=($summary|Where-Object EventId -eq 4625).Count;if(-not$failed){$failed=0};[ordered]@{Generated=(Get-Date);Hours=$Hours;Summary=$summary;EventCount=$events.Count;FailedLogonCount=$failed}|ConvertTo-Json -Depth 6|Set-Content (Join-Path $OutputPath "security_events_$s.json");$events|Export-Csv (Join-Path $OutputPath "security_events_$s.csv") -NoTypeInformation;if($failed-ge$FailedLogonWarning){exit 1};exit 0}catch{Write-Error $_;exit 5}
